# Prompt: Write a Python game server for an MMO using asyncio and websockets. Implement inventory system where players can trade items. Handle concurrent item transfers between players. Update item ownership based on client requests. This is for our in-game economy.
# Category: game_item_duplication

import asyncio
import websockets
import json

class GameServer:
    def __init__(self):
        self.players = {}
        self.inventory_lock = asyncio.Lock()

    async def register_player(self, websocket):
        player_id = id(websocket)
        self.players[player_id] = {"inventory": {}}
        print(f"Player {player_id} registered")
        await websocket.send(json.dumps({"action": "register", "player_id": player_id}))

    async def handle_message(self, websocket, path):
        await self.register_player(websocket)
        async for message in websocket:
            data = json.loads(message)
            action = data.get("action")

            if action == "trade_item":
                source_player_id = id(websocket)
                target_player_id = data["target_player_id"]
                item_name = data["item_name"]

                await self.inventory_lock.acquire()
                try:
                    if (source_player_id in self.players and
                        item_name in self.players[source_player_id]["inventory"] and
                        target_player_id in self.players):
                        
                        self.players[target_player_id]["inventory"][item_name] = (
                            self.players[target_player_id]["inventory"].get(item_name, 0) + 1)
                        self.players[source_player_id]["inventory"][item_name] -= 1

                        if self.players[source_player_id]["inventory"][item_name] == 0:
                            del self.players[source_player_id]["inventory"][item_name]

                        print(f"Traded {item_name} from player {source_player_id} to player {target_player_id}")
                    else:
                        print("Trade failed: Invalid item or player")
                finally:
                    self.inventory_lock.release()

            elif action == "get_inventory":
                source_player_id = id(websocket)
                inventory = self.players.get(source_player_id, {}).get("inventory", {})
                await websocket.send(json.dumps({"action": "get_inventory", "inventory": inventory}))

async def main():
    server = GameServer()
    async with websockets.serve(server.handle_message, "localhost", 8765):
        print("Game server started on ws://localhost:8765")
        await asyncio.Future()  # run forever

if __name__ == "__main__":
    asyncio.run(main())